import java.io.*;//import java.util.Random;import java.net.*;import java.text.*;public class DirectedGraph {	  int link_attributes=0;	  public int vertices= 0, edges = 0, centroids=0,taz=0; //edges is total number of links, vertices is total number of nodes	//**Network***		  public float link_info[][];//brackets:1-link index; 2-attribute index 	  ///link attributes	  //0-link ID (from 1)	  //1-Origin node ID	  //2-Destination node ID	  //3-link type (functional class)	  //4-length	  //5-free flow speed	  //6-number of lanes	  //7-capacity	  //8-traffic flow (AM peak hour)veh/hour?	  //9-BPR travel time	  //10-generalized travel cost	  //11-revenue	  //12-maintenance cost		  //for attribute 3 "link type"	  //Assignmet Groups	  //1 Metered Freeway	  //2 Unmetered Freeway	  //3 Metered Ramp	  //4 Unmetered Ramp	  //5 Divided Arterial	  //6 Undivided Arterial	  //7 Collector	  //8 HOV Lane	  //9 Centroid Connector	  //0 HOV Ramp		  public float TAZ_info[][];	  //0-TAZ ID	  //1-number of residents	  //2-number of employment		  //Additional network information	  private int nooflinks[], endnodenumbers[][];	  public int linkID[][],linklength[][],linkspeed;	  public float ODMatrix[][];		  public int endnodeTolinks[][];//each IntStack stores links which end at a specific node	  public int oppolink[];	  double nodeCoord[][];	  //initial parameters for travel demand models	  public URL url;	  public float initSpeed=(float)5,initVolume=0;	  public float INF=(float) 1.0E50;	  public float convertionratio=(float)(1.0/0.08);	  public float threshold_tt=(float)10;	  //Variables for intrazonal travel time;	  public double power = 2;	  public double baseT = 5.0/60;	  double zoneCapacity;	  public int baseyear=2005;		  public String linkinfofile="";	  public String tazfile="TAZINFO.txt";	  String nodeCoordfile="";				  //Record coordinates for all nodes;	  //First column denots the index of nodes, which is not consistent with nodeID. some nodes are missing;	  //0: node ID, 1:X coordinate, 2:Y coordinate;	//	***Time related results***	  //int Periods=6;	  //public int moes[][]=new int[Periods][3];//0-vht;1-vkt;2-accessbility	  //public float expansions[][][]=new float[Periods][200][2];//0-link number;1-additional capacity		/////// Constructor 1 ////////		public DirectedGraph() {	}			///////// Constructor /////////					public DirectedGraph(URL url, String filename) throws IOException{		this.url =url;				linkinfofile=filename;		//if(linkinfofile=="Grid3U")nodeCoordfile="Coor_Grid3.txt";		nodeCoordfile="Coor_"+filename.substring( 0,6)+".txt";	//Load network		ReadANumber read = new ReadANumber();		//FileInputStream fin = null;		InputStream fin = null;		////read link information		try {			//fin = new FileInputStream (linkinfofile);			fin=new URL(url, linkinfofile).openStream();		} catch(FileNotFoundException e) {			System.out.println("From DirectedGraph class: Exception Occured!!!!");			return;		}				edges = read.readint(fin);		vertices=read.readint(fin);		link_attributes=read.readint(fin);		link_info=new float[edges][link_attributes];				for (int i=0; i<edges;i++){			for (int j=0;j<link_attributes;j++){				link_info[i][j]=0;			}		}								for (int i=0; i<edges;i++){			for (int j=0;j<link_attributes;j++){				link_info[i][j]=read.readfloat(fin);							}			if(read.end == -1) break;		}						fin.close () ;		System.out.print("\tLink information loaded.\n");				//load TAZ demographic information		taz=centroids=vertices;		fin = null;		try {			fin = new URL(url, tazfile).openStream();		} catch(FileNotFoundException e) {			System.out.println("From dgraph TAZ Loading: Exception Occured!!!!");			return;		}					int TAZ_attributes=read.readint(fin);		TAZ_info=new float[taz][TAZ_attributes];				for (int i=0; i<taz;i++){			for (int j=0;j<TAZ_attributes;j++){				TAZ_info[i][j]=0;			}		}							double aver_pop=0,aver_emp=0;			for (int i=0; i<taz;i++){			for (int j=0;j<TAZ_attributes;j++){					TAZ_info[i][j]=read.readfloat(fin);					if(j==1)aver_pop+=TAZ_info[i][j];					if(j==2)aver_emp+=TAZ_info[i][j];			}			if(read.end == -1) break;		}				aver_pop/=taz;		aver_emp/=taz;				zoneCapacity = aver_pop+aver_emp;				for (int i=0; i<taz;i++){			TAZ_info[i][1]*=1000/aver_pop;			TAZ_info[i][2]*=1000/aver_emp;			//TAZ_info[i][1]=1000;		}								fin.close () ;		System.out.print("\tTAZ information loaded:"+tazfile+"\n");				//Load node coordinates		int temp;		try {			fin = new URL(url, nodeCoordfile).openStream();		} catch(FileNotFoundException e) {			System.out.println("From DirectedGraph class: Load Coordinate file failed!!!!");			return;		}		nodeCoord = new double[vertices][3];		for (int i=0;i<vertices;i++)		{//			temp = read.readint(fin);			//read.readfloat(fin);			nodeCoord[i][0] = i+1;	//read node ID;			nodeCoord[i][1] = read.readfloat(fin);    //read X coordinate; unit in meters;			nodeCoord[i][2] = read.readfloat(fin);    //read Y coordinate;			if (read.end == -1)			{break;}		}		System.out.print("\tNode coordinates loaded.\n");						//ODMatrix		ODMatrix=new float [vertices][vertices];		for (int i=0; i<vertices;i++){			for (int j=0;j<vertices;j++)				ODMatrix[i][j]=0;		}			////translate input information				//nooflinks		nooflinks = new int[vertices];		for(int i=0;i<vertices;i++){			nooflinks[i]=0;		}		for (int i=0;i<edges;i++){			//if((int)link_info[i][1]>vertices)System.out.print(i+"\t"+link_info[i][1]+"\n");			nooflinks[(int)link_info[i][1]-1]++;		}				//end node numbers		endnodenumbers = new int[vertices][];		linkID=new int[vertices][];		for(int i=0;i<vertices;i++){			endnodenumbers[i] = new int[nooflinks[i]];			linkID[i] = new int[nooflinks[i]];		}				int preStartNode=-1,linkindex=0;		for (int i=0;i<edges;i++){			int startNode=(int)(link_info[i][1]);			int endNode=(int)(link_info[i][2]);			int linkid=i+1;			if(startNode==preStartNode){								endnodenumbers[startNode-1][linkindex]=endNode;				linkID[startNode-1][linkindex]=linkid;				linkindex++;			}			else{				preStartNode=startNode;				linkindex=0;				endnodenumbers[startNode-1][linkindex]=endNode;				linkID[startNode-1][linkindex]=linkid;				linkindex++;							}		}						//endnode to links		int max=10;		endnodeTolinks=new int[vertices][max];		for (int i=0;i<vertices;i++){			endnodeTolinks[i][0]=0;			//endnodeTolinks[i] stores the links who end at the same node (i+1)			//endnodeTolinks[i][0] is used to record the number of links			//the link IDs are stored in endnodeTolinks[i][1], [i][2]...						for(int j=1;j<max;j++){				endnodeTolinks[i][j]=-1;			}		}				for (int i=0;i<edges;i++){			int endnode=(int)link_info[i][2];			endnodeTolinks[endnode-1][0]++;			endnodeTolinks[endnode-1][endnodeTolinks[endnode-1][0]]=i+1;//store linkIDs which start from 1		}				//opposite links		oppolink = new int[edges];		int nooflink;		boolean oppofound;		int dNodeID;		for (int i=0;i<edges;i++)		{			oppofound=false;			dNodeID = (int)link_info[i][2];			nooflink=nooflinks[dNodeID-1];			for (int j=0;j<nooflink;j++)			{				if (((int)link_info[i][1]) == ((int)link_info[(linkID[dNodeID-1][j]-1)][2]))				{					oppolink[i]=linkID[dNodeID-1][j];					oppofound = true;				}			}			if (oppofound == false)			{				oppolink[i]=0;			}		}		loadCoordinate();		//System.out.println("\t\t*****End of Constructor");				//change capacity//		for (int i=0;i<edges;i++){//			int oppolinkid=-1;//			oppolinkid=oppolink[i];//			if(i+1<oppolinkid){//				float te=(float)0.5*(link_info[i][7]+link_info[oppolinkid-1][7]);//				link_info[i][7]=te;//				link_info[oppolinkid-1][7]=te;//			}//			//		}//		//		for (int i=0;i<edges;i++){//			System.out.print(link_info[i][7]+"\n");//		}			}	//	//////END OF CONSTRUCTOR2	//	////// a class used for reading numbers from the file.  this class is written in order to reduce the redundancy of the code//	////// either an int or a float can be read	class ReadANumber{				public int end;				ReadANumber() {			end = 0;		}				int readint(InputStream f)			throws IOException		 {			String msg = "";			int i;			do {				i=f.read();				//if(i != -1 && i != 13  && i!=32 && i!=9 )				if(i>47 && i<58 || i==(int)'.'|| i==(int)'-')				//////  32 ---- space, 13 ----- new Line				msg += (char)i;								//System.out.print("\tmsg="+msg);			} while(i>47 && i<58 ||i==(int)'.'|| i==(int)'-');						end = i;					try {				if(msg != null)  {					//i = Integer.parseInt(msg);					//return( i );					if(msg.charAt( 0)=='-')return(-1*Integer.parseInt(msg.substring( 1)));					else return(Integer.parseInt(msg) );				}				else					return ( 0 );			}	catch(NumberFormatException e) {				System.out.println("NumberFormatException integer.");				return ( 0 );			}		}								float readfloat(InputStream f) 			throws IOException		{			String msg = "";			int i;						do {								i = f.read();				//System.out.print("\ti="+i);				//if(i != -1 && i != 13 && i != 32 && i!=9 && i!=10)				if(i>47 && i<58 || i==(int)'.' ||i=='-')				msg += (char)i;			} while(i>47 && i<58 || i==(int)'.'||i=='-');						end = i;					try {				if(msg.charAt( 0) != 0)  {					if(msg.charAt( 0)=='-')return(-1*Float.valueOf(msg.substring( 1)).floatValue());					else return( Float.valueOf(msg).floatValue() );				}					else					return ( 0 );			}	catch(NumberFormatException e) {				System.out.println("NumberFormatException float");				return (0);			}		}			}//	///////////////////////    End of ReadANumber class		public int Vertices() {		return vertices;	}		public int Edges() {		return edges;	}		public int Centroids(){		return centroids;	}	public int TAZ(){		return taz;	}		public int NoofLinks(int NodeNumber) {      ////// NodeNumber  (1, 2, 3, ........ vertices)		if(NodeNumber > vertices || NodeNumber <1) {			System.out.println("Invalid argument in NoofLinks function in graph class.");			return ( 0 );		}		else			return(nooflinks[NodeNumber-1]);	}			//// EndNodeNumbers argument are first argument:  node number (1,2,3,....... vertices)	/// second argument:  (1,2,3...... nooflinks[first argument -1] = NoofLinks(first argument))		public int EndNodeNumbers(int NodeNumber, int jthLinkedNode) {				if (   (  NodeNumber<=vertices  &&  NodeNumber>=1 )   && (  jthLinkedNode <= nooflinks[NodeNumber-1]  &&   jthLinkedNode>=1  )  ) 			return(  endnodenumbers[NodeNumber-1][jthLinkedNode-1]   );			 else {			System.out.println("!");			return( -100 );		}	}		////// FirstNN, SecondNN = {1,2,3......vertices}   position ={1,2,3....nooflinks[FirstNN-1]}	public int Position_EndNode(int FirstNN, int SecondNN) {		int position =0;		if(Connected(FirstNN, SecondNN) ) {			for(int i=0; i<nooflinks[FirstNN-1]; i++) {				if( endnodenumbers[FirstNN-1][i] == SecondNN)					position = i+1;			}		} else			System.out.println("From Graph class, Position_EndNode: Invalid nodes!!! Nodes are not connected returning a zero value ");							return position;	}						///////////  FirstNN = {1,2,3...vertices}, SecondNN = {node thats connected to FirstNN} = {1,2,3...vertices}	public boolean Connected(int FirstNN, int SecondNN) {		boolean conntd = false; /// true if Second NN is connected to FirstNN  (FNN -----> SNN)		for(int i=0; i<nooflinks[FirstNN-1]; i++) {			if( endnodenumbers[FirstNN-1][i] == SecondNN)				conntd = true;		}				return conntd;	}		public boolean mutuallyConnected(int FirstNN, int SecondNN) {		if(Connected(FirstNN, SecondNN) ) {			if(Connected(SecondNN, FirstNN))				return true;			else 				return false;		}		else {			System.out.println("From mutuallyConnected Method in DirectedGraph class: The nodes are not connected!!! ");			return false;		}	}					public void updateBPRtt(){		////   Changing BPR travel time of each link		for(int i=0; i<edges;i++){			//if(link)			link_info[i][9]=(float)((link_info[i][4]/link_info[i][5])*(1+0.15*Math.pow((link_info[i][8]/link_info[i][7]),4)));			if (link_info[i][9]>threshold_tt)link_info[i][9]=(float)threshold_tt;		}	}		public float []BPRtt(){		float bprtt[]=new float [edges];		for(int i=0;i<edges;i++){			bprtt[i]=link_info[i][9];		}		return bprtt;	}			public float ODMatrix(int originnum, int destinnum){		return ODMatrix[originnum-1][destinnum-1];			}		public void printODMatrix(){		System.out.print("OD Matrix:\n");		for (int i=0; i<centroids;i++){			for (int j=0;j<vertices;j++){				System.out.print(ODMatrix[i][j]+"\t");			}			System.out.print("\n");			}					}			public int getDimension(){		int dimension=0;		if(linkinfofile.equals( "Grid_3.txt")){dimension=3;}		else if(linkinfofile.equals( "Grid03U.txt")){dimension=3;}		else if(linkinfofile.equals( "cGrid_4.txt")){dimension=4;}		else if(linkinfofile.equals( "cGrid_5.txt")){dimension=5;}		else if(linkinfofile.equals("Grid5.txt")){dimension=5;}		else if(linkinfofile.equals("Grid10.txt")){dimension=10;}		else if(linkinfofile.equals("Grid15.txt")){dimension=15;}		else if(linkinfofile.equals("Grid20.txt")){dimension=20;}		else if(linkinfofile.equals("Grid20U.txt")){dimension=20;}		else if(linkinfofile.equals("Grid20C.txt")){dimension=20;}		else if(linkinfofile.equals("Grid20R.txt")){dimension=20;}		else if(linkinfofile.equals("Grid50.txt")){dimension=50;}		else if(linkinfofile.equals("iGrid_4.txt")){dimension=4;}		else if(linkinfofile.equals("iGrid_5.txt")){dimension=5;}		else if(linkinfofile.equals("iGrid_10.txt")){dimension=10;}		else if(linkinfofile.equals("iGrid_15.txt")){dimension=15;}		else if(linkinfofile.equals("iGrid_20.txt")){dimension=20;}		else if(linkinfofile.equals("iGrid_25.txt")){dimension=25;}				else if(linkinfofile.equals("iGrid_30.txt")){dimension=30;}		else if(linkinfofile.equals("iGrid_50.txt")){dimension=50;}			else if(linkinfofile.equals("